SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION fpa_hr_kep_money_amount_not (ai_year integer,ai_month integer,as_memno char,as_type char) RETURNS bigint AS $body$
DECLARE

  ldc_money_amount_not bigint;

BEGIN

  if upper(trim(both as_type)) = 'ML' then
    select sum(sc_kep_t_monthly_receive_det.money_amount_not) into STRICT ldc_money_amount_not
    from 	sc_kep_t_monthly_receive_det,
          sc_kep_t_monthly_receive
    where (sc_kep_t_monthly_receive.kep_method = 'SAL')
    and (sc_kep_t_monthly_receive.receipt_status = '0')
    and (sc_kep_t_monthly_receive.membership_no	=	sc_kep_t_monthly_receive_det.membership_no)
    and (sc_kep_t_monthly_receive.receive_year	=	sc_kep_t_monthly_receive_det.receive_year)
    and (sc_kep_t_monthly_receive.receive_month	=	sc_kep_t_monthly_receive_det.receive_month)
    and (sc_kep_t_monthly_receive.seq_no	=	sc_kep_t_monthly_receive_det.seq_no)
    and (sc_kep_t_monthly_receive.receive_year = ai_year)
    and (sc_kep_t_monthly_receive.receive_month = ai_month)
    and (sc_kep_t_monthly_receive.membership_no = as_memno )
    and (substr(trim(both sc_kep_t_monthly_receive_det.keeping_type_code),1,2) = 'ML');
  else
    select sum(sc_kep_t_monthly_receive_det.money_amount_not) into STRICT ldc_money_amount_not
    from 	sc_kep_t_monthly_receive_det,
          sc_kep_t_monthly_receive
    where (sc_kep_t_monthly_receive.kep_method = 'SAL')
    and (sc_kep_t_monthly_receive.receipt_status = '0')
    and (sc_kep_t_monthly_receive.membership_no	=	sc_kep_t_monthly_receive_det.membership_no)
    and (sc_kep_t_monthly_receive.receive_year	=	sc_kep_t_monthly_receive_det.receive_year)
    and (sc_kep_t_monthly_receive.receive_month	=	sc_kep_t_monthly_receive_det.receive_month)
    and (sc_kep_t_monthly_receive.seq_no	=	sc_kep_t_monthly_receive_det.seq_no)
    and (sc_kep_t_monthly_receive.receive_year = ai_year)
    and (sc_kep_t_monthly_receive.receive_month = ai_month)
    and (sc_kep_t_monthly_receive.membership_no = as_memno )
    and (substr(trim(both sc_kep_t_monthly_receive_det.keeping_type_code),1,2) <> 'ML');
  end if;



return ldc_money_amount_not;

exception when others then CALL spa_dberror('FPA_HR_KEP_MONEY_AMOUNT_NOT');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
